ALGORITHM Max-Bipartite-Matching(G, L, R, E)
BEGIN
  // Create flow network
  V' ← L ∪ R ∪ {s, t}
  E' ← ∅

  // Add edges from source to left vertices
  FOR each u in L
    E' ← E' ∪ {(s, u) with capacity 1}
  END FOR

  // Add edges from left to right (original edges)
  FOR each (u,v) in E
    E' ← E' ∪ {(u, v) with capacity 1}
  END FOR

  // Add edges from right to sink
  FOR each v in R
    E' ← E' ∪ {(v, t) with capacity 1}
  END FOR

  // Compute max flow using Edmonds-Karp
  maxFlow ← Edmonds-Karp(V', E', s, t)

  // Extract matching from flow
  matching ← ∅
  FOR each edge (u,v) where u∈L, v∈R
    IF flow[u,v] = 1 THEN
      matching ← matching ∪ {(u,v)}
    ENDIF
  END FOR

  RETURN matching
END
